import Foundation

struct CategoryContent5 {
    static let aiEthics = CategoryData(
        id: "ai_ethics", name: "AI Right & Wrong", icon: "shield.checkered", colorName: "aiRed",
        description: "Fairness, safety, and making good choices with AI",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 4,
        unlockRequirement: .completeCategoryMinimum("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "ae_l1", title: "Understanding AI Bias", description: "When AI isn't fair", categoryId: "ai_ethics", questions: [
        Question(id: "ae1_q1", type: .multipleChoice, questionText: "AI bias in models from companies like Anthropic, Google, OpenAI, and Meta most often originates from:", options: ["Biased or unrepresentative training data", "Intentionally malicious programming", "Random errors in the model's code", "Mistakes made by individual end users"], correctAnswer: "Biased or unrepresentative training data", explanation: "Most AI bias stems from training data that reflects historical inequalities or underrepresents certain groups. This affects models across the industry."),
        Question(id: "ae1_q2", type: .trueFalse, questionText: "AI systems, including those built by leading companies like Anthropic and Google DeepMind, can unintentionally perpetuate racial and gender biases.", options: ["True", "False"], correctAnswer: "True", explanation: "If trained on historically biased data, any AI system can reproduce and even amplify societal biases, regardless of the developer's intentions."),
        Question(id: "ae1_q3", type: .scenarioJudgment, questionText: "Amazon discontinued an AI hiring tool after discovering it penalized resumes containing the word 'women's' because historical data skewed male. Was this the right call?", options: ["Yes, the tool was perpetuating gender discrimination", "No, it was simply reflecting accurate historical patterns", "It depends on the specific job roles involved"], correctAnswer: "Yes, the tool was perpetuating gender discrimination", explanation: "Amazon's case is a landmark example of AI perpetuating historical bias. The company was right to discontinue the tool rather than deploy a discriminatory system."),
        Question(id: "ae1_q4", type: .fillInBlank, questionText: "AI __________ occurs when a system systematically produces unfair outcomes that disadvantage certain demographic groups.", options: ["bias", "latency", "complexity", "variance"], correctAnswer: "bias", explanation: "AI bias leads to systematically unfair outcomes. Organizations like the Algorithmic Justice League work to identify and combat bias across AI systems."),
        Question(id: "ae1_q5", type: .multipleChoice, questionText: "Which approach is most effective at reducing bias in AI systems?", options: ["Diverse development teams combined with representative training data", "Using a single large and homogeneous data source", "Relying on the algorithm to self-correct over time", "Simply increasing the model's parameter count"], correctAnswer: "Diverse development teams combined with representative training data", explanation: "Research from Anthropic, Google DeepMind, and academic institutions shows that diverse teams catch biases that homogeneous teams miss, and representative data reduces skewed learning."),
        Question(id: "ae1_q6", type: .multipleChoice, questionText: "What does 'algorithmic fairness' mean in the context of AI development?", options: ["Designing AI systems that treat all demographic groups equitably", "Ensuring all AI algorithms run at the same processing speed", "Reducing the computational complexity of AI models", "Making all training data publicly available for review"], correctAnswer: "Designing AI systems that treat all demographic groups equitably", explanation: "Algorithmic fairness is the practice of ensuring AI systems do not systematically disadvantage any group. It is a core research focus at Anthropic, Google DeepMind, and many universities.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "ae_l2", title: "Deepfakes & Misinformation", description: "AI-generated deception", categoryId: "ai_ethics", questions: [
        Question(id: "ae2_q1", type: .multipleChoice, questionText: "A deepfake is:", options: ["AI-generated synthetic video, audio, or images depicting real people", "A specialized deep learning software framework", "An advanced method of data encryption", "A technique for debugging neural networks"], correctAnswer: "AI-generated synthetic video, audio, or images depicting real people", explanation: "Deepfakes use generative AI to create realistic but fabricated media of real people. Tools from companies and open-source projects have made creation increasingly accessible."),
        Question(id: "ae2_q2", type: .trueFalse, questionText: "Modern deepfakes generated by advanced AI models are always easy for humans to identify without specialized tools.", options: ["True", "False"], correctAnswer: "False", explanation: "State-of-the-art generative models produce deepfakes that are increasingly difficult for humans to detect, driving demand for AI-powered detection tools from companies like Microsoft and Intel."),
        Question(id: "ae2_q3", type: .scenarioJudgment, questionText: "During an election, a deepfake video of a candidate making inflammatory statements goes viral on social media. What should platforms do?", options: ["Flag and remove the content with an explanation of why it is synthetic", "Leave it up since it could be protected speech", "It depends on whether the content is entertaining"], correctAnswer: "Flag and remove the content with an explanation of why it is synthetic", explanation: "Deepfake political content is a form of disinformation that can undermine democratic processes. The EU AI Act and multiple national regulations now require labeling of synthetic media."),
        Question(id: "ae2_q4", type: .multipleChoice, questionText: "Which technology is primarily used to detect AI-generated deepfakes?", options: ["Other AI models trained to spot synthetic artifacts", "Traditional blockchain verification systems", "Standard file compression analysis tools", "Conventional digital watermarking methods"], correctAnswer: "Other AI models trained to spot synthetic artifacts", explanation: "Companies like Microsoft, Intel, and Sensity use AI-powered detection tools that analyze subtle artifacts in synthetic media — fighting AI with AI."),
        Question(id: "ae2_q5", type: .fillInBlank, questionText: "AI-generated __________ — false or misleading content created at scale — is one of the most significant societal challenges posed by generative AI.", options: ["misinformation", "education", "entertainment", "software"], correctAnswer: "misinformation", explanation: "Generative models from various companies make it easier to create convincing misinformation at scale. The EU AI Act, US executive orders, and the G7 Hiroshima AI Process all address this threat."),
        Question(id: "ae2_q6", type: .matchPairs, questionText: "Match each deepfake threat to its real-world impact:", matchPairs: [
            MatchPair(term: "Political deepfakes", definition: "Undermining elections"),
            MatchPair(term: "Voice cloning scams", definition: "Impersonating people by phone"),
            MatchPair(term: "Synthetic news articles", definition: "Spreading false information"),
            MatchPair(term: "Face-swap identity fraud", definition: "Impersonating someone's likeness")
        ], explanation: "Deepfakes pose threats ranging from election interference to personal fraud. Governments worldwide are enacting legislation to address these risks.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "ae_l3", title: "AI Alignment", description: "Making AI do what we want", categoryId: "ai_ethics", questions: [
        Question(id: "ae3_q1", type: .multipleChoice, questionText: "AI alignment, a core research focus at Anthropic and other labs, refers to:", options: ["Ensuring AI systems pursue goals consistent with human values and intentions", "Optimizing AI model performance on standard benchmarks", "Coordinating multiple AI systems to work in parallel", "Standardizing development practices across the AI industry"], correctAnswer: "Ensuring AI systems pursue goals consistent with human values and intentions", explanation: "Alignment is the challenge of making AI systems beneficial and consistent with human values. Anthropic was founded specifically to focus on AI safety and alignment research."),
        Question(id: "ae3_q2", type: .trueFalse, questionText: "An AI model that scores perfectly on performance benchmarks is automatically aligned with human values.", options: ["True", "False"], correctAnswer: "False", explanation: "An AI can optimize perfectly for a given objective but still cause harm if that objective does not capture human values. This gap is central to alignment research at Anthropic, Google DeepMind, and OpenAI."),
        Question(id: "ae3_q3", type: .fillInBlank, questionText: "The __________ problem, studied extensively by researchers at Anthropic and Google DeepMind, describes the challenge of specifying goals for AI that truly match human intent.", options: ["alignment", "optimization", "scalability", "deployment"], correctAnswer: "alignment", explanation: "The alignment problem is one of the most important open challenges in AI safety. Anthropic's Constitutional AI and Google DeepMind's research programs are among the leading efforts to address it."),
        Question(id: "ae3_q4", type: .scenarioJudgment, questionText: "An AI tasked with maximizing paper clip production converts all available resources into paper clips, including those needed by humans. What went wrong?", options: ["The AI's objective was dangerously misaligned with human wellbeing", "The AI was running too slowly to notice the problem", "Nothing went wrong — it achieved its stated goal", "It depends on how many paper clips were actually produced"], correctAnswer: "The AI's objective was dangerously misaligned with human wellbeing", explanation: "This is philosopher Nick Bostrom's famous 'paperclip maximizer' thought experiment, illustrating why AI alignment matters. It is a foundational concept in AI safety research."),
        Question(id: "ae3_q5", type: .multipleChoice, questionText: "RLHF, a technique used by Anthropic, OpenAI, and Google to align AI models, stands for:", options: ["Reinforcement Learning from Human Feedback", "Rapid Learning for Hardware Functions", "Random Learning from Historical Files", "Real-time Language for Human Facts"], correctAnswer: "Reinforcement Learning from Human Feedback", explanation: "RLHF incorporates human feedback to align model behavior with human preferences. Anthropic extended this approach with Constitutional AI (CAI), and Google uses similar techniques for Gemini."),
        Question(id: "ae3_q6", type: .multipleChoice, questionText: "Why is AI alignment considered fundamentally difficult by researchers at Anthropic, Google DeepMind, and elsewhere?", options: ["Human values are complex, context-dependent, and hard to formalize in code", "Current computing hardware is not powerful enough for alignment", "There is not enough training data available for alignment research", "AI models are still too small to exhibit alignment-relevant behaviors"], correctAnswer: "Human values are complex, context-dependent, and hard to formalize in code", explanation: "Human values are nuanced, culturally varied, and sometimes contradictory — making them extremely challenging to encode. This is why Anthropic, Google DeepMind, and others invest heavily in alignment research.")
    ], order: 2, difficulty: .advanced)
    static let lesson4 = LessonData(id: "ae_l4", title: "Privacy & Surveillance", description: "AI and your personal data", categoryId: "ai_ethics", questions: [
        Question(id: "ae4_q1", type: .multipleChoice, questionText: "Facial recognition AI, deployed by companies and governments worldwide, raises concerns about:", options: ["Mass surveillance and erosion of personal privacy", "Increased cloud data storage costs", "Slower image processing on mobile devices", "Reduced quality of digital photographs"], correctAnswer: "Mass surveillance and erosion of personal privacy", explanation: "Facial recognition enables tracking individuals without consent. The EU AI Act classifies real-time biometric surveillance in public spaces as a high-risk or prohibited AI use."),
        Question(id: "ae4_q2", type: .trueFalse, questionText: "Multiple cities and the European Union have restricted or banned certain uses of AI-powered facial recognition technology.", options: ["True", "False"], correctAnswer: "True", explanation: "San Francisco, Boston, and several European cities have restricted facial recognition. The EU AI Act bans real-time biometric identification in public spaces with limited exceptions."),
        Question(id: "ae4_q3", type: .fillInBlank, questionText: "AI systems that collect and analyze personal data must comply with data __________ regulations such as GDPR and CCPA.", options: ["privacy", "performance", "accessibility", "transparency"], correctAnswer: "privacy", explanation: "Laws like the EU's GDPR, California's CCPA, Brazil's LGPD, and China's PIPL regulate how AI systems collect and use personal data across different jurisdictions."),
        Question(id: "ae4_q4", type: .scenarioJudgment, questionText: "A retail chain uses AI cameras to analyze customers' facial expressions while shopping to optimize product placement, without informing shoppers. Is this ethical?", options: ["No, it is an invasion of privacy without informed consent", "Yes, it is standard business innovation and optimization", "It depends on whether the store has a privacy policy posted"], correctAnswer: "No, it is an invasion of privacy without informed consent", explanation: "Monitoring emotions without explicit consent violates privacy principles embedded in GDPR, the EU AI Act, and ethical AI frameworks from organizations worldwide."),
        Question(id: "ae4_q5", type: .multipleChoice, questionText: "What does the GDPR principle of 'data minimization' require of AI systems?", options: ["Collecting only the minimum personal data necessary for the stated purpose", "Minimizing the cost of data storage infrastructure", "Deleting all collected data immediately after processing", "Using the smallest possible database architecture"], correctAnswer: "Collecting only the minimum personal data necessary for the stated purpose", explanation: "Data minimization is a core GDPR principle: AI systems should only collect what is strictly needed. This principle is echoed in privacy frameworks worldwide."),
        Question(id: "ae4_q6", type: .multipleChoice, questionText: "The EU AI Act classifies AI systems into risk tiers. Which category faces the strictest requirements?", options: ["High-risk AI systems like those used in healthcare and law enforcement", "Minimal-risk AI systems like spam filters and game AI", "General-purpose AI models used for creative writing", "Open-source AI models distributed freely online"], correctAnswer: "High-risk AI systems like those used in healthcare and law enforcement", explanation: "The EU AI Act imposes the strictest requirements on high-risk AI used in areas like biometric identification, critical infrastructure, law enforcement, and healthcare.")
    ], order: 3, difficulty: .intermediate)
    static let lesson5 = LessonData(id: "ae_l5", title: "AI Regulation", description: "Laws governing AI", categoryId: "ai_ethics", questions: [
        Question(id: "ae5_q1", type: .multipleChoice, questionText: "The EU AI Act, the world's first comprehensive AI law, classifies AI systems primarily by:", options: ["Risk level, from minimal to unacceptable", "Processing speed and computational cost", "The company's annual revenue", "The total number of end users"], correctAnswer: "Risk level, from minimal to unacceptable", explanation: "The EU AI Act uses a risk-based framework: unacceptable risk (banned), high risk (strict requirements), limited risk (transparency obligations), and minimal risk (no restrictions)."),
        Question(id: "ae5_q2", type: .trueFalse, questionText: "There is currently a single unified global standard for AI regulation that all countries follow.", options: ["True", "False"], correctAnswer: "False", explanation: "AI regulation varies significantly: the EU has the AI Act, the US takes a sector-specific approach, China mandates algorithm registration, and the OECD promotes voluntary principles."),
        Question(id: "ae5_q3", type: .matchPairs, questionText: "Match each jurisdiction to its AI governance approach:", matchPairs: [
            MatchPair(term: "EU AI Act", definition: "Risk-based classification system"),
            MatchPair(term: "US approach", definition: "Sector-specific guidelines"),
            MatchPair(term: "China", definition: "Government-controlled AI governance"),
            MatchPair(term: "OECD AI Principles", definition: "International voluntary guidelines")
        ], explanation: "Different regions take fundamentally different approaches to AI regulation, creating a complex global landscape for companies like Anthropic, Google, Meta, and OpenAI."),
        Question(id: "ae5_q4", type: .fillInBlank, questionText: "AI __________ aims to balance technological innovation with the protection of individual rights and societal wellbeing.", options: ["regulation", "innovation", "standardization", "optimization"], correctAnswer: "regulation", explanation: "AI regulation frameworks like the EU AI Act, US executive orders, and the G7 Hiroshima AI Process all seek to balance innovation with safety and rights."),
        Question(id: "ae5_q5", type: .scenarioJudgment, questionText: "A government mandates that all AI systems must be fully explainable before deployment in any context. Is this a sound policy?", options: ["It depends — the right level of explainability varies by application and risk", "Yes, full transparency should be required universally", "No, explainability requirements always stifle innovation"], correctAnswer: "It depends — the right level of explainability varies by application and risk", explanation: "The EU AI Act wisely takes a risk-based approach: medical diagnostic AI needs more explainability than a movie recommendation system. A blanket requirement could be impractical."),
        Question(id: "ae5_q6", type: .multipleChoice, questionText: "What does 'AI transparency' mean in regulatory frameworks like the EU AI Act?", options: ["Making AI decision-making processes understandable to affected stakeholders", "Publishing all proprietary AI training data openly", "Making all AI models available as open-source software", "Reducing AI model complexity to a minimum"], correctAnswer: "Making AI decision-making processes understandable to affected stakeholders", explanation: "AI transparency means people affected by AI decisions can understand how and why those decisions were made. The EU AI Act requires transparency for high-risk systems.")
    ], order: 4, difficulty: .advanced)
    static let lesson6 = LessonData(id: "ae_l6", title: "Responsible AI Development", description: "Building AI the right way", categoryId: "ai_ethics", questions: [
        Question(id: "ae6_q1", type: .multipleChoice, questionText: "Which set of principles forms the foundation of responsible AI development at companies like Anthropic, Google, and Microsoft?", options: ["Fairness, accountability, transparency, and safety", "Speed, cost reduction, profit, and market share", "Secrecy, complexity, scale, and exclusivity", "Marketing, growth, valuation, and branding"], correctAnswer: "Fairness, accountability, transparency, and safety", explanation: "Responsible AI is built on these core principles. Anthropic emphasizes safety-first development, Google publishes AI principles, and Microsoft has a Responsible AI Standard."),
        Question(id: "ae6_q2", type: .trueFalse, questionText: "Companies developing AI have no ethical obligations beyond meeting the minimum legal requirements in their jurisdiction.", options: ["True", "False"], correctAnswer: "False", explanation: "Ethical AI development goes beyond legal compliance. Anthropic, Google DeepMind, and other leading labs have published voluntary commitments and principles that exceed current legal requirements."),
        Question(id: "ae6_q3", type: .fillInBlank, questionText: "An AI __________ board, adopted by companies like Google and Microsoft, helps organizations evaluate the ethical implications of AI deployment.", options: ["ethics", "advisory", "strategy", "innovation"], correctAnswer: "ethics", explanation: "AI ethics boards provide guidance on responsible development and deployment. Google's AI ethics framework and Microsoft's Responsible AI program both include advisory structures."),
        Question(id: "ae6_q4", type: .scenarioJudgment, questionText: "An AI company discovers significant bias in their model just weeks before a major product launch. Fixing it would delay the launch by three months. Should they delay?", options: ["Yes, fix the bias before releasing the product to users", "No, launch on schedule and patch the bias in a future update", "It depends on whether competitors will launch first"], correctAnswer: "Yes, fix the bias before releasing the product to users", explanation: "Deploying a known biased system can cause real harm to affected groups. Anthropic, Google, and other responsible AI companies have delayed releases to address safety concerns."),
        Question(id: "ae6_q5", type: .multipleChoice, questionText: "What is an AI impact assessment, as recommended by the EU AI Act and OECD guidelines?", options: ["A systematic evaluation of an AI system's potential effects on people and society", "A benchmark comparison of AI model accuracy scores", "An audit of AI system infrastructure and hosting costs", "A measurement of training data volume and diversity"], correctAnswer: "A systematic evaluation of an AI system's potential effects on people and society", explanation: "Impact assessments help identify and mitigate potential harms before deployment. The EU AI Act requires them for high-risk AI systems, and the OECD recommends them broadly."),
        Question(id: "ae6_q6", type: .multipleChoice, questionText: "According to responsible AI practices followed by leading labs, what is most important after an AI system is deployed?", options: ["Ongoing monitoring for bias, errors, and unintended behaviors", "Only testing the system once before its initial launch", "Assuming the AI will continue to perform correctly indefinitely", "Avoiding all risk by limiting the system's capabilities"], correctAnswer: "Ongoing monitoring for bias, errors, and unintended behaviors", explanation: "AI systems can develop issues as real-world data shifts over time. Anthropic, Google, and OpenAI all emphasize continuous monitoring and evaluation after deployment.")
    ], order: 5, difficulty: .advanced)
}
